SELECT e.employeeid, e.firstname, e.lastname, e.salary, e.reportsto, SUM(od.unitprice * od.quantity) AS order_total FROM employees e JOIN employeeterritories et ON e.employeeid = et.employeeid JOIN orders o ON e.employeeid = o.employeeid JOIN "order details" od ON o.orderid = od.orderid WHERE (strftime('%Y', o.shippeddate) = '1997') AND (e.salary > (SELECT AVG(salary) FROM employees)) GROUP BY e.employeeid, e.firstname, e.lastname, e.salary, e.reportsto
